insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('05508b03-8b11-4f57-88f1-5bba3e954cde','e324b8c0-c9c7-498c-b444-87c043bab50d','“Senti sua falta, esperei exatamente no lugar que prometemos.”','Explicação: Antes de irem para o exército, os membros pediram para o ARMY confiar neles e esperar no mesmo lugar. Esta frase é a resposta direta do fandom a esse pedido.',null,null,202,0,'2026-06-12 14:03:52.941805+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
