insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('15202a75-2a50-4787-9768-56acb40076ec','e324b8c0-c9c7-498c-b444-87c043bab50d','“Sete anos depois, juntos novamente sob a mesma lua".','Explicação: Nós que vivemos do outro lado do mundo, temos a impressão de nos sentir mais distantes do que todos os outros porquê não olhamos o mesmo sol ou a mesma lua que os meninos. Essa frase busca representar que estaremos olhando pra mesma lua ao mesmo tempo e também que isso aconteceu mesmo depois de tanto tempo de espera.',null,null,111,0,'2026-06-12 14:11:31.378322+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
