insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('1c399a2c-cfb9-4ca5-a6a9-d03b0628f8fe','e324b8c0-c9c7-498c-b444-87c043bab50d','"Juntos nadamos contra a correnteza, próximos do amanhã."','Explicação: Fazendo referência a “Swim” e “Tomorrow”, que nos ensina a não atropelarmos o presente e que o amanhã sempre chega.',null,null,31,0,'2026-06-12 14:06:02.851108+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('1fe1550c-6121-4043-8460-6df035e00083','e324b8c0-c9c7-498c-b444-87c043bab50d','"Nos encontraram como estranhos. Nos uniram como família."','Explicação: Antes de conhecer o BTS, cada ARMY era apenas uma pessoa qualquer vivendo sua própria vida. Quando conheceram o BTS, eles formaram uma comunidade que vai muito além de fãs. Pessoas de lugares diferentes passaram a se conectar e compartilhar suas experiências graças ao mesmo amor pelo BTS.',null,null,43,0,'2026-06-12 14:12:01.916185+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('20de3861-e0c8-4a5e-a176-2a502ad185f4','e324b8c0-c9c7-498c-b444-87c043bab50d','“Nosso amor atravessou oceanos. Vamos nadar juntos em direção ao Sol.”','Explicação: A primeira parte é sobre a Coreia e o Brasil estarem em lados opostos do globo e fala sobre o nosso amor superar qualquer barreira. A segunda parte é um jogo de palavras com “Swim” e “Into The Sun”, que dá continuidade à primeira parte da frase.',null,null,726,0,'2026-06-12 14:09:02.310218+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('24563ea0-294c-4592-8867-c46d95d26692','e324b8c0-c9c7-498c-b444-87c043bab50d','"De Seul ao Brasil, nosso coração continua o mesmo."','Explicação: A frase simboliza a conexão entre BTS e ARMY que permaneceu forte ao longo dos anos, independentemente da distância entre Coreia do Sul e Brasil. A mensagem celebra o reencontro após anos de espera e destaca que o amor compartilhado atravessa oceanos, idiomas e fronteiras.',null,null,62,0,'2026-06-12 14:09:18.292689+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
