insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('6632e038-6933-4a6c-9f56-baa38a9f999c','e324b8c0-c9c7-498c-b444-87c043bab50d','O mundo nos separou, mas nossos corações sempre estiveram juntos.','Explicação: É inspirada principalmente em “Please”, na conexão emocional que permanece mesmo quando as circunstâncias afastam as pessoas. Em um vínculo e desejo de estar perto que nem o mundo é capaz de superar. Também pode ser uma resposta ao verso “You’ll never love me like the way you did before“ de Come Over, que apesar do tempo que passou e tudo que mudou, o amor permanece.',null,null,42,0,'2026-06-12 14:15:22.636102+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('6bc1d6f1-6ab5-4dd8-8171-6db1a5ae4350','e324b8c0-c9c7-498c-b444-87c043bab50d','"Ao fim do longo inverno, a nossa primavera finalmente voltou para casa."','Explicação: Ela representa a longa e dolorosa espera (o inverno) do fandom brasileiro pelo retorno dos meninos. Dizer que "a primavera finalmente voltou para casa" significa que, com o retorno do BTS ao Brasil, o frio da saudade acabou e eles estão de volta ao lugar onde são profundamente amados e acolhidos.',null,null,819,0,'2026-06-12 14:04:23.967512+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('6e59c4cf-9e5e-4915-8724-b239b57e2ee9','e324b8c0-c9c7-498c-b444-87c043bab50d','“Obrigada por serem o nosso conforto quando precisávamos de força.”','Explicação: Nem sempre precisávamos que alguém resolvesse os nossos problemas; às vezes, só precisávamos de conforto para continuar. Essa frase é um agradecimento ao BTS por oferecerem esse conforto para milhões de pessoas através das suas músicas e mensagens.',null,null,56,0,'2026-06-12 14:09:36.793014+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('6feebded-b855-47e5-9e6b-02832c4c9b22','e324b8c0-c9c7-498c-b444-87c043bab50d','“Obrigado por navegarem de volta até nós depois desses 7 anos.”','Explicação: Receber o BTS de volta ao Brasil após a sua última passagem, há 7 anos, é o marco do encontro de almas que sempre foram destinadas a estar juntas. Esperamos por um amor que sempre foi maior que a distância e que agora navegará de volta para casa: para as ARMYs.',null,null,673,0,'2026-06-12 14:07:03.833092+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
