insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('79f7d16d-6394-41e7-946d-0e1ea9fe00bb','e324b8c0-c9c7-498c-b444-87c043bab50d','“Nosso amor floresceu mesmo durante o inverno.”','Explicação: Inspirada em Spring Day, a música retrata o inverno como uma metáfora da saudade. A espera é tão dolorosa que mesmo sendo verão nos sentimos vazios e gelados. Quando dizemos que florescemos mesmo durante o inverno, significa que apesar da saudade apertar, nosso amor cresceu (floresceu) ainda mais.',null,null,110,0,'2026-06-12 14:04:45.298142+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
