insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('db28da5d-2420-4161-b5df-c91f340c4268','e324b8c0-c9c7-498c-b444-87c043bab50d','“De lados opostos do mundo, mas debaixo do mesmo céu.”','Explicação: Mesmo estando em lugares diferentes, vivendo em lados opostos do mundo, quando olhamos para o céu, estamos conectados de alguma forma. É uma forma simples e profunda, de lembrar que nunca estivemos sozinhos.',null,null,798,0,'2026-06-12 14:05:21.508461+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('e0a64426-fc37-4bf4-b632-63d0857742a2','e324b8c0-c9c7-498c-b444-87c043bab50d','"A distância foi apenas um capítulo para nosso reencontro."','Explicação: Essa frase representa a distância e o reencontro. Como a saudade fez parte de nossas rotinas, porém, em vez de enxergar isso como uma separação, transformamos em mais um capítulo da nossa história.',null,null,102,0,'2026-06-12 14:12:13.991308+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('e0ebeb0b-8772-47b8-b391-6de365a076ed','e324b8c0-c9c7-498c-b444-87c043bab50d','“A nossa canção de amor é a melodia de suas almas”','Explicação: A frase funciona como uma resposta para a frase de divulgação do Arirang “What is your love song?”. A intenção é dizer que a nossa canção de amor são os próprios meninos.',null,null,39,0,'2026-06-12 14:14:20.115559+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
