insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('e7a8a41e-1c04-4f61-bd8c-d1e72826856e','e324b8c0-c9c7-498c-b444-87c043bab50d','“Vocês vivem em mais vidas do que imaginam.”','Explicação: É uma forma de dizer: “Vocês sempre falam sobre o quanto o ARMY mudou a vida de vocês. Mas vocês também vivem na nossa muito mais do que imaginam.”',null,null,148,0,'2026-06-12 14:03:23.257767+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('eac2bd5d-5416-4db3-bf60-ff3a8929000b','e324b8c0-c9c7-498c-b444-87c043bab50d','"Vocês são a nossa primavera depois de todo inverno."','Explicação: A primavera simboliza renovação, esperança, felicidade e o florescer após um período difícil, enquanto o inverno simboliza a saudade, espera e os momentos em que sentimos a distância. O BTS é uma fonte de conforto e inspiração durante diferentes fases da vida, e, assim como a primavera chega depois do inverno, a presença e a música deles trazem alegria, força e esperança depois de momentos difíceis.',null,null,42,0,'2026-06-12 14:11:51.019491+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
