insert into public.opcoes_votacao (id,votacao_id,titulo,descricao,imagem_url,imagem,votos_count,votos,created_at,hb_phrase_group,hb_frase,position) values ('efad3863-d527-4de3-97bb-20e07cf6439c','e324b8c0-c9c7-498c-b444-87c043bab50d','"Nosso amanhecer está em vocês."','Explicação:O amanhecer marca o retorno do sol após a escuridão da noite. Nesse sentido, os meninos são a luz que sempre encontraremos nos momentos difíceis.',null,null,30,0,'2026-06-12 14:16:17.466925+00','frase1',1,0) on conflict (id) do update set votacao_id=excluded.votacao_id, titulo=excluded.titulo, descricao=excluded.descricao, imagem_url=excluded.imagem_url, imagem=excluded.imagem, votos_count=excluded.votos_count, votos=excluded.votos, hb_phrase_group=excluded.hb_phrase_group, hb_frase=excluded.hb_frase, position=excluded.position;
insert into public.solo_projects (id,solo_member_id,title,description,image_url,cover_image,link_url,status,position,created_at) values ('392c0977-3049-4af9-b5fa-69f20ff73fe3','2ba0e8a5-2ecf-4848-8092-104e318098af','JIMTOBER - Ponto de Ônibus','Painel publicitário próximo ao MorumBIS com mensagens de carinho enviadas por fãs para celebrar o aniversário do JIMIN.','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1782839784189-ef8bd4330e0dc-Captura-de-tela-2026-06-30-141445.png','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1782839784189-ef8bd4330e0dc-Captura-de-tela-2026-06-30-141445.png','https://x.com/info_jimin/status/2063689969588228476?s=20','em_colaboracao',0,'2026-06-30 17:16:34.880386+00') on conflict (id) do update set solo_member_id=excluded.solo_member_id, title=excluded.title, description=excluded.description, image_url=excluded.image_url, cover_image=excluded.cover_image, link_url=excluded.link_url, status=excluded.status, position=excluded.position;
insert into public.solo_projects (id,solo_member_id,title,description,image_url,cover_image,link_url,status,position,created_at) values ('5db477d1-6ef7-4dea-a404-8e4e3b2806fc','fcb785e6-7681-4f69-b150-2a1d7d9e2696','FUTURE''S GONNA BE OKAY','Projeto de arrecadação em homenagem ao Yoongi financiará a reforma da sala de Musicoterapia do Instituto Autismos. O espaço levará o nome de Sala Min Yoongi, simbolizando inclusão, acolhimento, esperança e transformação.','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781852110779-7687e68c520e58-Captura-de-tela-2026-06-19-035441.png','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781852110779-7687e68c520e58-Captura-de-tela-2026-06-19-035441.png','https://www.instagram.com/p/DZI8N6sjkc6/?utm_source=ig_web_copy_link&igsh=NTc4MTIwNjQ2YQ==','em_colaboracao',0,'2026-06-14 23:02:06.25282+00') on conflict (id) do update set solo_member_id=excluded.solo_member_id, title=excluded.title, description=excluded.description, image_url=excluded.image_url, cover_image=excluded.cover_image, link_url=excluded.link_url, status=excluded.status, position=excluded.position;
insert into public.solo_projects (id,solo_member_id,title,description,image_url,cover_image,link_url,status,position,created_at) values ('72435200-48d7-4e8c-8ed2-ce3f14c8aafb','fcb785e6-7681-4f69-b150-2a1d7d9e2696','COME OVER','O projeto Come Over tem como objetivo tornar o estádio num oceano de corações roxos com mensagens de amor ao SUGA!','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781852046335-c26fede38a877-Captura-de-tela-2026-06-19-035332.png','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781852046335-c26fede38a877-Captura-de-tela-2026-06-19-035332.png','https://x.com/streamforsuga93/status/2060496499524436475/photo/1','em_colaboracao',0,'2026-06-14 23:07:19.888495+00') on conflict (id) do update set solo_member_id=excluded.solo_member_id, title=excluded.title, description=excluded.description, image_url=excluded.image_url, cover_image=excluded.cover_image, link_url=excluded.link_url, status=excluded.status, position=excluded.position;
insert into public.solo_projects (id,solo_member_id,title,description,image_url,cover_image,link_url,status,position,created_at) values ('8510ce7f-0d5b-44ef-bf69-c88e79f7c20c','875ec0ea-529f-4288-8133-f2f4b3e91e41','A NOITE ESTRELADA','Transformar o Morumbis em uma verdadeira noite estrelada inspirada na obra de Van Gogh, durante o momento de discurso do Taehyung. Criar um mar de luzes e estrelas pelo estádio, proporcionando uma visão especial e emocionante, para que ele possa sentir todo o carinho do público brasileiro.','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781854237502-6890417f867388-taehyung-1.jpg','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781854237502-6890417f867388-taehyung-1.jpg','https://sites.google.com/view/projeto-noite-estrelada/in%C3%ADcio?authuser=9','em_colaboracao',0,'2026-06-14 23:11:17.226015+00') on conflict (id) do update set solo_member_id=excluded.solo_member_id, title=excluded.title, description=excluded.description, image_url=excluded.image_url, cover_image=excluded.cover_image, link_url=excluded.link_url, status=excluded.status, position=excluded.position;
insert into public.solo_projects (id,solo_member_id,title,description,image_url,cover_image,link_url,status,position,created_at) values ('85460135-2d06-4401-a985-fd9e967aab78','4c6631c3-3cfd-4b09-8f7b-66632e653dee','A ARTE DO SER HUMANO','A Arte de Ser Humano é uma exposição artística inspirada na trajetória de Kim Namjoon (RM/BTS), criada por fãs para proporcionar uma experiência sensorial e emocional que conecta arte, música, natureza e reflexão.','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781852197034-d19b023cd9a328-projeto-namjoon.jpg','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781852197034-d19b023cd9a328-projeto-namjoon.jpg','https://x.com/knj_brasil/status/2056753115022442890?s=20','em_colaboracao',0,'2026-06-14 23:15:06.961379+00') on conflict (id) do update set solo_member_id=excluded.solo_member_id, title=excluded.title, description=excluded.description, image_url=excluded.image_url, cover_image=excluded.cover_image, link_url=excluded.link_url, status=excluded.status, position=excluded.position;
insert into public.solo_projects (id,solo_member_id,title,description,image_url,cover_image,link_url,status,position,created_at) values ('9bfe8c64-3267-4c4a-95cc-72ac1281fc16','875ec0ea-529f-4288-8133-f2f4b3e91e41','THV WORLD TOUR BTS','Projeto da KTHBR dedicado ao Taehyung durante a vinda do BTS ao Brasil. A ação contará com um painel próximo ao MorumBIS e a distribuição de brindes exclusivos nas filas do evento.','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781853976007-6b6dfb2f1e2d4-taehyung-2.jpg','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781853976007-6b6dfb2f1e2d4-taehyung-2.jpg','https://x.com/ktaehbrasil/status/2058215066554466444?s=20','em_colaboracao',0,'2026-06-14 23:19:58.566159+00') on conflict (id) do update set solo_member_id=excluded.solo_member_id, title=excluded.title, description=excluded.description, image_url=excluded.image_url, cover_image=excluded.cover_image, link_url=excluded.link_url, status=excluded.status, position=excluded.position;
insert into public.solo_projects (id,solo_member_id,title,description,image_url,cover_image,link_url,status,position,created_at) values ('a9687a7a-f19c-480b-95ab-0dcaf1e82b73','2ba0e8a5-2ecf-4848-8092-104e318098af','Sob a mesma Lua','Reunir ARMYs para uma comemoração mega especial. Aproveitar um momento de boa energia, café quentinho e muito amor pelo nosso JIMIN, na Hyo Jeong Cafeteria.','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1782839856265-8a4b41b787005-Captura-de-tela-2026-06-30-141420.png','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1782839856265-8a4b41b787005-Captura-de-tela-2026-06-30-141420.png','https://x.com/info_jimin/status/2069563679498965291?s=20','em_colaboracao',0,'2026-06-30 17:17:48.181654+00') on conflict (id) do update set solo_member_id=excluded.solo_member_id, title=excluded.title, description=excluded.description, image_url=excluded.image_url, cover_image=excluded.cover_image, link_url=excluded.link_url, status=excluded.status, position=excluded.position;
insert into public.solo_projects (id,solo_member_id,title,description,image_url,cover_image,link_url,status,position,created_at) values ('bff7ec06-8050-43dc-bf58-edebf832551e','2ba0e8a5-2ecf-4848-8092-104e318098af','FLORES PARA JIMIN','“Flores para Jimin” é um projeto que convida o ARMY a erguer flores amarelas durante o discurso de encerramento do Jimin nos três dias de show e cantar parabéns, criando uma homenagem coletiva e emocionante em celebração ao seu aniversário.','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781853838249-2f5da5fc3e3dd8-jimin.jpg','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781853838249-2f5da5fc3e3dd8-jimin.jpg','https://www.instagram.com/p/DXNQVBjCToB/?utm_source=ig_web_copy_link&igsh=NTc4MTIwNjQ2YQ==','em_colaboracao',1,'2026-06-14 22:46:06.734416+00') on conflict (id) do update set solo_member_id=excluded.solo_member_id, title=excluded.title, description=excluded.description, image_url=excluded.image_url, cover_image=excluded.cover_image, link_url=excluded.link_url, status=excluded.status, position=excluded.position;
insert into public.solo_projects (id,solo_member_id,title,description,image_url,cover_image,link_url,status,position,created_at) values ('c60add3e-6ef8-498a-b49c-f5b2515f4eae','9ed54a4b-e087-4c04-abc1-403698eb8587','THE ASTRONAUT','O Projeto The Astronaut é uma ação que será realizada no dia 28/10, para homenagear Seokjin pelos 4 anos de lançamento de The Astronaut. A iniciativa consiste em celebrar esse marco especial, demonstrando amor, apoio e reconhecimento.','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781853265698-90ba927fc626f8-jin.jpg','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781853265698-90ba927fc626f8-jin.jpg','https://x.com/jinnieacess/status/2052531536357114068?s=20','em_colaboracao',0,'2026-06-14 23:16:59.118671+00') on conflict (id) do update set solo_member_id=excluded.solo_member_id, title=excluded.title, description=excluded.description, image_url=excluded.image_url, cover_image=excluded.cover_image, link_url=excluded.link_url, status=excluded.status, position=excluded.position;
insert into public.solo_projects (id,solo_member_id,title,description,image_url,cover_image,link_url,status,position,created_at) values ('d83d7a08-664b-4a65-94a8-36f46580d52a','acc3ebb3-90ab-497e-8ccb-0cd30ef957f5','HOPE IN MOTION','Hope In Motion é um projeto que transformará um espaço próximo ao MorumBIS, em São Paulo, em um mural grafitado em homenagem ao J-HOPE, com apresentações especiais de breakdance em datas selecionadas.','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781853454675-bf76914a4bb648-hobi.jpg','https://menaprzrrftribfyymmq.supabase.co/storage/v1/object/public/barmy360-images/soloProjectImage/1781853454675-bf76914a4bb648-hobi.jpg','https://drive.google.com/file/d/13--jqluYbJA0duDdFjogNtc-l_wTnLS2/view?usp=drivesdk','em_colaboracao',0,'2026-06-14 23:22:06.021739+00') on conflict (id) do update set solo_member_id=excluded.solo_member_id, title=excluded.title, description=excluded.description, image_url=excluded.image_url, cover_image=excluded.cover_image, link_url=excluded.link_url, status=excluded.status, position=excluded.position;
